import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length != 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path sourcePath = Paths.get(sourceDirectory);

        if (!Files.exists(sourcePath)) {
            System.err.println("Source directory does not exist: " + sourceDirectory);
            System.exit(1);
        }

        // Create a JavaSymbolSolver for type resolution
        TypeSolver typeSolver = new JavaParserTypeSolver(sourcePath.toFile());
        JavaSymbolSolver symbolSolver = new JavaSymbolSolver(typeSolver);
        StaticJavaParser.getConfiguration().setSymbolResolver(symbolSolver);

        // Process all Java files in the directory
        Files.walk(sourcePath)
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(Main::processFile);
    }

    private static void processFile(Path filePath) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(filePath.toFile());
            boolean modified = cu.accept(new JerseyClientBuilderTransformationVisitor(), null);

            if (modified) {
                cu.setStorage(filePath);
                cu.save();
                System.out.println("Updated: " + filePath);
            }
        } catch (Exception e) {
            System.err.println("Error processing file " + filePath + ": " + e.getMessage());
        }
    }

    private static class JerseyClientBuilderTransformationVisitor extends ModifierVisitor<Boolean> {
        @Override
        public Visitable visit(ObjectCreationExpr n, Boolean arg) {
            // Check if this is a JerseyClientBuilder constructor call with Environment parameter
            if (n.getType().getNameAsString().equals("JerseyClientBuilder")) {
                // Check if it's a constructor with one Environment parameter
                if (n.getArguments().size() == 1) {
                    Expression argument = n.getArguments().get(0);
                    if (argument instanceof NameExpr) {
                        // Get the full class name to ensure it's the right one
                        String className = n.getType().asString();
                        if (className.equals("io.dropwizard.client.JerseyClientBuilder")) {
                            // Create new constructor call without the environment parameter
                            ObjectCreationExpr newConstructor = new ObjectCreationExpr();
                            newConstructor.setType(n.getType());

                            // Add the environment parameter to the .using() call instead
                            // Replace: new JerseyClientBuilder(env)
                            // With: new JerseyClientBuilder().using(env)
                            ExpressionStmt stmt = (ExpressionStmt) this.getParentNode()
                                    .orElseThrow(() -> new RuntimeException("Parent node not found"));

                            // Create the method chain: new JerseyClientBuilder().using(env)
                            MethodCallExpr usingCall = new MethodCallExpr(
                                    new ObjectCreationExpr()
                                            .setType(n.getType()),
                                    "using",
                                    NodeList.nodeList(argument)
                            );

                            // Replace the entire expression with the new one
                            return usingCall;
                        }
                    }
                }
            }
            return super.visit(n, arg);
        }
